void SpawnAsteroid()
{
    Vector3 pos = Random.onUnitSphere * spawnRadius;
    float size = Random.Range(0.5f, 2.5f);

    GameObject ast = Instantiate(asteroidPrefab, pos, Random.rotation);
    ast.transform.localScale = Vector3.one * size;

    Rigidbody rb = ast.GetComponent<Rigidbody>();
    rb.AddForce(Random.onUnitSphere * Random.Range(5,15), ForceMode.Impulse);
}

using Unity.VisualScripting;
//using UnityEditor.Build;
using UnityEngine;

public class house2door : MonoBehaviour
{
    [SerializeField] private Animator DoorOpen = null;
    [SerializeField] private Animator DoorClosed = null;

    [SerializeField] private bool openTrigger = false;
    [SerializeField] private bool closeTrigger = false;

    [SerializeField] private string doorOpen = "house2";
    [SerializeField] private string doorClose = "DoorClose";

    private void Start()
    {   
        DoorOpen = GetComponent<Animator>();
    }

    private void OnTriggerEnter(Collider other)
    {   
        if (!openTrigger)
        {   
            Debug.Log("trigger door open");
            DoorOpen.Play("house2", 0, 0f);
            //gameObject.SetActive(false);
        }
        else if (closeTrigger)
        {   
            DoorClosed.Play("doorClose", 0, 0.0f);
            gameObject.SetActive(false);
        }
    }
}

using Unity.Mathematics;
using UnityEngine;

public class Gun : MonoBehaviour
{
    private Animator GunAnimation;
   [SerializeField] private Rigidbody Bullet;
   [SerializeField] private GameObject FireLocation;
    private string gunanim = "gunanim";
    private float cooldown;

    private void Start()
    {   
        GunAnimation = GetComponent<Animator>();
    }
    void Update()
    { 
        cooldown = cooldown - Time.deltaTime;
        if (Input.GetMouseButtonDown(0))
        {
            if (cooldown <= 0)
            {
                GunAnimation.Play("gun", 0, 0f);
            Rigidbody bulletclone;
            bulletclone = Instantiate(Bullet, FireLocation.transform.position, FireLocation.transform.rotation);
            bulletclone.linearVelocity = transform.TransformDirection(Vector3.forward * 10);
            cooldown = 0.2f;
            }
        }
    }
}

GameObject GetRandomPrefab()
{
    float totalChance = 0f;
    foreach (float c in chance)
        totalChance += c;

    float randomValue = Random.Range(0f, totalChance);

    int i = 0;
    foreach (GameObject p in prefabs)
    {
        if (randomValue < chance[i])
        {
            index = i;
            return p;
        }
        randomValue -= chance[i];
        i++;
    }
    return null;
}

void Start()
{
    SelectedPrefab = GetRandomPrefab();
    if (SelectedPrefab != null)
        Instantiate(SelectedPrefab, transform.position, transform.rotation);

    SpawnGem GemScript = SelectedPrefab.GetComponent<SpawnGem>();
    if (GemScript != null)
        FossilText.text = GemScript.FossilInfo;
    else
        FossilText.text = "No text about the fossil found!";
}

public void Next()
{
    ClickSound();
    _fossils[currentImageIndex].SetActive(false);
    currentImageIndex++;
    if (currentImageIndex == _fossils.Count)
        currentImageIndex = 0;
    _fossils[currentImageIndex].SetActive(true);
}

public void Previous()
{
    ClickSound();
    _fossils[currentImageIndex].SetActive(false);
    currentImageIndex--;
    if (currentImageIndex == -1)
        currentImageIndex = _fossils.Count - 1;
    _fossils[currentImageIndex].SetActive(true);
}

